// ============================================
// FUNÇÃO AUXILIAR - NORMALIZA TEXTO
// ============================================
function normalize(text) {
  if (!text) return '';
  return text
    .toString()
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "") // remove acentos
    .trim();
}

// ============================================
// MAPEAMENTO - EXPERIÊNCIA INCORPORAÇÃO
// ============================================
function mapExperienciaIncorporacao(input) {
  const text = normalize(input);

  if (text.includes("nunca") || text.includes("nao incorporou")) {
    return "Nunca incorporou";
  }

  if (text.includes("pretende") || text.includes("pensando") || text.includes("futuro")) {
    return "Pretende incorporar no futuro";
  }

  if (text.includes("ativo") || text.includes("ja incorporou") || text.includes("atua")) {
    return "Incorporador ativo";
  }

  return "Nunca incorporou"; // fallback seguro
}

// ============================================
// MAPEAMENTO - FAMILIARIDADE MURILO
// ============================================
function mapFamiliaridadeMurilo(input) {
  const text = normalize(input);

  if (text.includes("nunca ouviu")) {
    return "Nunca ouviu falar";
  }

  if (text.includes("superficial")) {
    return "Conhece superficialmente";
  }

  if (text.includes("acompanha") || text.includes("segue") || text.includes("instagram")) {
    return "Já acompanha nas redes";
  }

  if (text.includes("evento") || text.includes("imersao")) {
    return "Já participou de evento";
  }

  if (text.includes("cliente") || text.includes("comprou")) {
    return "Já é cliente";
  }

  return "Nunca ouviu falar"; // fallback seguro
}

// ============================================
// MAPEAMENTO - EXPERIÊNCIA MENTORIA
// ============================================
function mapExperienciaMentoria(input) {
  const text = normalize(input);

  if (text.includes("nunca")) {
    return "Nunca participou";
  }

  if (text.includes("outro setor")) {
    return "Já participou em outro setor";
  }

  if (text.includes("mercado imobiliario") || text.includes("imobiliario")) {
    return "Já participou no mercado imobiliário";
  }

  if (text.includes("murilo")) {
    return "Já participou com o Murilo";
  }

  return "Nunca participou"; // fallback seguro
}

function mapDesafiosBarreiras(input) {
  if (!input) return "";

  const cleaned = input
    .toString()
    .trim()
    .replace(/\n+/g, " ")
    .replace(/\s+/g, " ");

  if (cleaned === "\\n") return "";

  return cleaned;
}

// ============================================
// INPUT DA IA
