//   familiaridade_murilo: "...",
//   experiencia_mentoria: "..."
// }

// ============================================
// OUTPUT FINAL TRATADO
// ============================================
return [
  {
    telefone: inputIA.telefone,
    experiencia_incorporacao: mapExperienciaIncorporacao(inputIA.experiencia_incorporacao),
    familiaridade_murilo: mapFamiliaridadeMurilo(inputIA.familiaridade_murilo),
    experiencia_mentoria: mapExperienciaMentoria(inputIA.participacao_imersão_mentoria),
    desafios_barreiras: mapDesafiosBarreiras(inputIA.desafios_barreiras)
  }
];
